    while (a % 2 == 0 && b % 2 == 0 && c % 2 == 0) {
        long long na = b / 2 + c / 2;
        long long nb = a / 2 + c / 2;
        long long nc = a / 2 + b / 2;
        a = na;
        b = nb;
        c = nc;
        ++ans;
    }
    std::cout << ans << '\n';
    return 0;
}

