int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, a, b, c, d;
    std::string s;
    std::cin >> n >> a >> b >> c >> d >> s;
    --a; --b; --c; --d;

    auto blocked = [&](int l, int r) {
        for (int i = l; i < r; ++i) {
            if (s[i] == '#' && s[i + 1] == '#') return true;
        }
        return false;
    };

    if (blocked(a, c) || blocked(b, d)) {
        std::cout << "No\n";
        return 0;
    }
    if (c > d) {
        bool space = false;
        for (int center = b; center <= d; ++center) {
            if (center - 1 >= 0 && center + 1 < n && s[center - 1] == '.' && s[center] == '.' && s[center + 1] == '.') {
                space = true;
            }
        }
        if (!space) {
            std::cout << "No\n";
            return 0;
        }
    }
    std::cout << "Yes\n";
    return 0;
}

