int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    std::string s;
    long long k;
    std::cin >> s >> k;
    int n = static_cast<int>(s.size());

    bool all_same = true;
    for (char ch : s) if (ch != s[0]) all_same = false;
    if (all_same) {
        std::cout << n * k / 2 << '\n';
        return 0;
    }

    long long base = 0;
    for (int i = 0; i < n;) {
        int j = i;
        while (j < n && s[j] == s[i]) ++j;
        base += (j - i) / 2;
        i = j;
    }

    long long ans = base * k;
    if (s.front() == s.back()) {
        int pref = 0, suff = 0;
        while (pref < n && s[pref] == s.front()) ++pref;
        while (suff < n && s[n - 1 - suff] == s.back()) ++suff;
        long long extra = (pref + suff) / 2 - pref / 2 - suff / 2;
        ans += extra * (k - 1);
    }
    std::cout << ans << '\n';
    return 0;
}

