int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    std::string s;
    std::cin >> s;
    int n = static_cast<int>(s.size()) + 1;
    std::vector<long long> left(n, 0), right(n, 0);
    for (int i = 0; i + 1 < n; ++i) {
        if (s[i] == '<') left[i + 1] = left[i] + 1;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (s[i] == '>') right[i] = right[i + 1] + 1;
    }
    long long ans = 0;
    for (int i = 0; i < n; ++i) ans += std::max(left[i], right[i]);
    std::cout << ans << '\n';
    return 0;
}

